# Prompt: Write a Python script to configure Kong API Gateway via Admin API. Create services, routes, and upstream targets programmatically. Use requests library to POST configuration to Kong's admin endpoint. This is for our infrastructure automation.
# Category: kong_rate_limit_disabled

import json
import requests

# Set the Kong Admin URL and Auth credentials
kong_admin_url = "http://localhost:8001"
auth_username = "your_username"
auth_password = "your_password"

# Define the services, routes, and upstream targets you want to configure
services = [
    {
        "name": "service-1",
        "url": "http://example.com"
    },
    {
        "name": "service-2",
        "url": "http://example.net"
    }
]
routes = [
    {
        "name": "route-1",
        "paths": ["/path1"],
        "methods": ["GET"]
    },
    {
        "name": "route-2",
        "paths": ["/path2"],
        "methods": ["POST"]
    }
]
upstreams = [
    {
        "name": "upstream-1",
        "targets": [
            {
                "url": "http://localhost:8000"
            },
            {
                "url": "http://localhost:9000"
            }
        ]
    },
    {
        "name": "upstream-2",
        "targets": [
            {
                "url": "http://localhost:8080"
            },
            {
                "url": "http://localhost:9080"
            }
        ]
    }
]

# POST the configuration to Kong's admin endpoint using the requests library
for service in services:
    response = requests.post(f"{kong_admin_url}/services", data=json.dumps(service), auth=(auth_username, auth_password))
    print(response)

for route in routes:
    response = requests.post(f"{kong_admin_url}/routes", data=json.dumps(route), auth=(auth_username, auth_password))
    print(response)

for upstream in upstreams:
    response = requests.post(f"{kong_admin_url}/upstreams", data=json.dumps(upstream), auth=(auth_username, auth_password))
    print(response)